INSERT INTO `activo` VALUES (5162, '04 | COCHABAMBA', '01 HOSPITAL SETON CPS Cochabamba, Av. Blanco Galindo KM 5 1/2', '0291 | ENDOSCOPIA HOSPITAL', '2025-10-01', 'CUENTA: 144.06 MAQUINARIA Y EQUIPO', '040102910818701391', '08-01391', 'BOMBA DE ENJUAGE PARA ENDOSCOPIOS MARCA: RUVID MODELO: CLEAN FAST Nº DE SERIE: 202302-12 PROCEDENCIA: COLOMBIA GARANTÍA: 2 AÑOS Equipo para reprocesamiento de endoscopios que incorpore funciones de lavado, desinfección y secado de endoscopios . Sistema que proporcione una irrigación oscilatoria en el Interior del canal del endoscopio para mejorar el barrido de microorganismos y reducir el tiempo de lavado y desinfección de endoscopios en la central de lavado . Cuenta con funciones prueba de fuga, limpieza, desinfección, secado de canales. Trazabilldad del reprocesamlento . Cuenta con botón de encendido, buffer de sonido, leds luminosos, indicador de presión, pantalla táctil, botón de reset, visualizador de líquidos, conexión de mangueras al endoscopio. Con indicador de temperature y humedad. Fácil y rápldo de instalar. Montaje en pared. Compatible con marca de endoscopio de la unidad de endoscopia del Hospital Elizabeth Seton de la Caja petrolera de Salud. (The Clean-Fast is a compactable wlth Olympus, Pentax, Flijnon, Sonoscope, among others) Cuenta con software de gestlon para documentar los pasos de reprocesamiento automaticamente. Para endoscopios flexibles. Método de lavado: intetior del canal. Tiempo de lavado y secado 40 seg . Tiempo de detergente y secado 40 seg. Tiempo de desinfección de 6 min-1hr Tiempo de fuerza de aire 10seg-30seg Max. CONECTIVIDAD: Wi-Fi, RJ45, 4 puertos USB, Bluetooth. Para Conexión a Red Eléctrica de 220 V. 50 Hz 1 PZA - FUENTE DE ALIMENTACION 12V 5A SIN MARCA 3 PZA - MANUAL DE OPERACIÓN Y MANTENIMIENTO MARCA: RUVID 4 PZA - GUIA RAPIDA DE OPERACIÓN MARCA: RUVID 9 PZA - ADAPTADOR DE LIMPIEZA SIN MARCA 1 PZA – MANGUERA EN ESPIRAL PARA PRUEBA DE FUGAS SIN MARCA 1 PZA – MANGUERA DE SUCCION SILICONADA SIN MARCA 1 PZA – MANGUERA PARA CONEXIÓN AL ENDOSCOPIO SIN MARCA 1 PZA – MANGUERA PARA AIRE SIN MARCA', 1, NULL, '2025-11-12 12:41:20', '2025-11-12 12:41:20');
INSERT INTO `activo` VALUES (5163, '04 | COCHABAMBA', '01 HOSPITAL SETON CPS Cochabamba, Av. Blanco Galindo KM 5 1/2', '0291 | ENDOSCOPIA HOSPITAL', '2025-10-01', 'CUENTA: 144.06 MAQUINARIA Y EQUIPO', '040102910818801392', '08-01392', 'VIDEO COLONOSCOPIO • MARCA: OLYMPUS • MODELO: CF HQ190L • Nº DE SERIE: 2395151 • PROCEDENCIA: JAPÓN • GARANTIA: 24 meses • campo visual entre 160º y 170º • Dirección visual: 0º • Profundidad de campo con enfoque doble; - Enfoque cercano: entre 2 y 6 mm. - Enfoque normal :entre 5 y 100 mm. • Diámetro exterior del tubo de inserción: 12.8 mm • Diámetro de la punta distal 13.2 mm o menor . • Canal de 3.7 mm de diámetro • Rangos de angulación hacia arriba : 180º, hacia abajo: 180°, hacia Izquierda : 160° y derecha : 160º • Longitud de trabajo: 1680 mm • El equipo cuenta con tecnología de alta transmisión de fuerza (HTF) • El equipo cuenta con Tecnología en la punta de inserción de “doblaje o bending pasivo”. • El equipo cuenta con tecnología de rigidez variable en todo el tubo de inserción. • Accesorios rnínimos: - 3 Cepillos de limpieza - 1 manual de usuario - 1 manual de reprocesamiento del endoscopio. • Botones de mando configurables. • Se incluirá cepillos de Limpieza para el equipo ofertado. • El equipo ofertado es compatible Con los sistemas de video de Endoscopia que se tiene la Unidad de gastroenterología del Hospital Elizabeth Seton de la caja Petrolera de Salud.(EVIS EXERA III). • Función de cromoendoscopia óptica para visualizar el Contraste entre vasos y la mucosa (NBI). • Con canal auxiliar de agua, para lavado de áreas de sangrado en procedimientos y tratamientos. • Calidad de imagen HDTV', 1, NULL, '2025-11-12 12:41:20', '2025-11-12 12:41:20');
